import { useState, useEffect } from "react";
import axios from 'axios';
import { Container } from "react-bootstrap";

const CLIENT_ID = "addd071529764e90bb548a5b11edc35f";
const AUTH_URL = `https://accounts.spotify.com/authorize?
					client_id=addd071529764e90bb548a5b11edc35f
					&response_type=code
					&redirect_uri=http://localhost:3000/
					&scope=streaming%20user-read-email%20user-read-private%20user-library-read
							%20user-library-modify%20user-read-playback-state%20user-modify-playback-state
							%20user-follow-read%20playlist-read-private%20playlist-read-collaborative
							%20playlist-modify-public%20user-read-playback-position%20user-top-read
							%20user-read-recently-played`;

export const Login = () => {
	return (
		<Container>
			<h1>Login</h1>

			<Button><a className="authorize" href={AUTH_URL}>Authorize</a></Button>
		</Container>
	);
};
